async function run(params, api) {
  var theme = params.theme || 'default';
  var lines = [];
  lines.push('---');
  lines.push('marp: true');
  lines.push('theme: ' + theme);
  lines.push('paginate: true');
  lines.push('header: "' + params.title.replace(/"/g, '\\"') + '"');
  if (params.author) lines.push('footer: "' + params.author.replace(/"/g, '\\"') + '"');
  lines.push('---');
  lines.push('');
  lines.push('# ' + params.title);
  if (params.author) lines.push('\n**' + params.author + '**');
  lines.push('');
  for (var i = 0; i < params.slides.length; i++) {
    var s = params.slides[i];
    lines.push('---');
    lines.push('');
    lines.push('## ' + s.heading);
    lines.push('');
    lines.push(s.content);
    if (s.notes) {
      lines.push('');
      lines.push('<!--');
      lines.push(s.notes);
      lines.push('-->');
    }
    lines.push('');
  }
  lines.push('---');
  lines.push('');
  lines.push('# Thank You');
  lines.push('');
  var md = lines.join('\n');
  api.log('Generated ' + params.slides.length + ' slides');
  return md;
}
